export interface ArrayGeometryNode {
  kind: 'array';
  target: FamilyInstanceRefNode;
  mode: 'linear' | 'radial';
  countParam: string;
  spacing: { kind: 'fixed_mm'; mm: number } | { kind: 'fit_total'; totalLengthParam: string };
