export function resolveNestedFamilyInstance(
  node: FamilyInstanceRefNode,
  hostParams: HostParams,
  catalog: FamilyCatalogLookup,
  depth: number = 0,
  detailLevelOrOptions?: ResolverDetailLevel | FamilyResolveVisibilityOptions,
